const files = fs.readdirSync('.').filter((file) => file.endsWith('.html'));
const failures = [];

for (const file of files) {
  const html = fs.readFileSync(file, 'utf8');
  const hasLucide = html.includes('data-lucide=');
  const hasInlineSvgButton = /<(?:a|button)[^>]*>[\\s\\S]*?<svg[\\s\\S]*?<\\/(?:a|button)>/.test(html);
  const hasButtonIcon = /<(?:a|button)[^>]*>[\\s\\S]*?(?:data-lucide=|<svg)[\\s\\S]*?<\\/(?:a|button)>/.test(html);

  if (hasLucide && !/lucide\\.createIcons\\s*\\(/.test(html)) {
    failures.push(`${file}: missing lucide.createIcons()`);
  }

  if (hasLucide && !/https:\\/\\/unpkg\\.com\\/lucide@latest\\/dist\\/umd\\/lucide\\.min\\.js/.test(html)) {
    failures.push(`${file}: missing lucide script`);
  }

  if (hasButtonIcon && !hasLucide && !hasInlineSvgButton) {
    failures.push(`${file}: button icon markup not detected`);
  }

  if (/data-lucide="\\$\\{/.test(html) && !file.endsWith('.html')) {
    failures.push(`${file}: unresolved lucide template token`);
  }
}

if (failures.length) {
  console.error(failures.join('\\n'));
  process.exit(1);
}

console.log(`button icon check passed for ${files.length} html files`);

